import{_ as o,c as t,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"關於：OpenCodeDocs 簡介 | opencodedocs","description":"學習 OpenCodeDocs，了解 AI 生態第一教學站。深入解析開源專案，提供原始碼驅動、100% 可執行的高品質教學。","frontmatter":{"title":"關於：OpenCodeDocs 簡介 | opencodedocs","sidebarTitle":"了解專案願景","subtitle":"關於：OpenCodeDocs 簡介 | opencodedocs","description":"學習 OpenCodeDocs，了解 AI 生態第一教學站。深入解析開源專案，提供原始碼驅動、100% 可執行的高品質教學。"},"headers":[],"relativePath":"zh-tw/about.md","filePath":"zh-tw/about.md"}'),n={name:"zh-tw/about.md"};function s(i,e,c,l,d,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="關於-opencodedocs" tabindex="-1">關於 OpenCodeDocs <a class="header-anchor" href="#關於-opencodedocs" aria-label="Permalink to &quot;關於 OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>AI 生態第一教學站 · 原始碼驅動 · 100% 可執行</strong></p></blockquote><h2 id="我們的願景" tabindex="-1">我們的願景 <a class="header-anchor" href="#我們的願景" aria-label="Permalink to &quot;我們的願景&quot;">​</a></h2><p>AI 工具迭代快速，官方文件落後，網上教學過時——我們要改變這一切。</p><p>OpenCodeDocs 深入解析開源專案原始碼與官方範例，提煉核心邏輯，並透過自動化驗證確保每一行程式碼都能執行。</p><p>當專案更新時，我們的教學同步更新。每篇教學都清楚標註 Git Commit 版本，讓你知道程式碼基於哪個版本產生。</p><p><strong>我們的目標是成為 AI 工具圈的「Verified Standard」。</strong></p><h2 id="開源協議" tabindex="-1">開源協議 <a class="header-anchor" href="#開源協議" aria-label="Permalink to &quot;開源協議&quot;">​</a></h2><p>我們相信開放帶來信任。歡迎社群貢獻、糾錯、補充。</p><h3 id="教學內容" tabindex="-1">教學內容 <a class="header-anchor" href="#教學內容" aria-label="Permalink to &quot;教學內容&quot;">​</a></h3><p><strong>協議</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> 姓名標示 - 非商業性使用 - 相同方式分享。允許轉載和改編，但需註明出處，不得用於商業目的，且需以相同協議分享。</p><h3 id="建置工具" tabindex="-1">建置工具 <a class="header-anchor" href="#建置工具" aria-label="Permalink to &quot;建置工具&quot;">​</a></h3><p><strong>VitePress</strong>: 本專案使用 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> 建置。<br> 感謝 VitePress 團隊提供如此優秀的靜態網站產生器。</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">查看 GitHub 儲存庫</a></p><h2 id="聯絡我們" tabindex="-1">聯絡我們 <a class="header-anchor" href="#聯絡我們" aria-label="Permalink to &quot;聯絡我們&quot;">​</a></h2><ul><li><strong>電子郵件</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const g=o(n,[["render",s]]);export{b as __pageData,g as default};
